parameters.jsCode:
const body = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const payload = body.payload || body;
const obj = payload.object || {};

const meetingId = obj.id || obj.meeting_id || 'unknown';
const topic = obj.topic || 'Untitled Meeting';
const hostEmail = obj.host_email || payload.host_email || 'unknown';
const hostName = config.hostName || hostEmail;
const startTime = obj.start_time || new Date().toISOString();
const durationMinutes = obj.duration || 0;
const participants = obj.participants || [];

const meetingStart = new Date(startTime);
const lateThreshold = parseInt(config.lateThresholdMinutes) || 5;

const attendanceRows = [];
let attendedCount = 0;
let lateCount = 0;

participants.forEach(p => {
  const name = p.user_name || p.name || 'Unknown';
  const email = p.user_email || p.email || 'No email';
  const joinTime = p.join_time ? new Date(p.join_time) : null;
  const leaveTime = p.leave_time ? new Date(p.leave_time) : null;
  const stayDuration = p.duration || 0;

  let joinDelayMin = 0;
  let status = 'Attended';

  if (joinTime) {
    joinDelayMin = Math.round((joinTime - meetingStart) / 60000);
    if (joinDelayMin > lateThreshold) {
      status = 'Late';
      lateCount++;
    } else {
      attendedCount++;
    }
  } else {
    status = 'Attended';
    attendedCount++;
  }

  const stayMinutes = Math.round(stayDuration / 60);
  const joinTimeStr = joinTime ? joinTime.toISOString().replace('T',' ').substring(0,16) : 'N/A';
  const leaveTimeStr = leaveTime ? leaveTime.toISOString().replace('T',' ').substring(0,16) : 'N/A';

  attendanceRows.push({
    meetingId,
    meetingTopic: topic,
    hostEmail,
    meetingDate: meetingStart.toISOString().split('T')[0],
    meetingStartTime: meetingStart.toISOString().replace('T',' ').substring(0,16),
    meetingDurationMin: durationMinutes,
    participantName: name,
    participantEmail: email,
    joinTime: joinTimeStr,
    leaveTime: leaveTimeStr,
    stayDuration: `${stayMinutes} min`,
    joinDelayMin: joinDelayMin,
    status: status,
    loggedAt: new Date().toISOString().replace('T',' ').substring(0,16)
  });
});

const totalParticipants = participants.length;

return attendanceRows.map((row, index) => ({
  json: {
    ...row,
    isFirstRow: index === 0,
    totalParticipants,
    attendedCount,
    lateCount,
    topic,
    meetingId,
    hostName,
    hostEmail,
    telegramChatId: config.telegramChatId,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    clickupListId: config.clickupListId,
    meetingDurationMin: durationMinutes,
    meetingDate: meetingStart.toISOString().split('T')[0],
    lateThresholdMinutes: config.lateThresholdMinutes
  }
}));

